package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.assertEquals;
import org.mockito.Mockito;
import static org.mockito.Mockito.when;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testGetIgnoreEmptyLines() throws Exception {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n", null, null, false, false);

        // Using reflection to access private field
        Field ignoreEmptyLinesField = CSVFormat.class.getDeclaredField("ignoreEmptyLines");
        ignoreEmptyLinesField.setAccessible(true);
        ignoreEmptyLinesField.setBoolean(csvFormat, true);

        // When
        boolean result = csvFormat.getIgnoreEmptyLines();

        // Then
        assertEquals(true, result);
    }
}
